    @php
        $oldModal = old('member_modal');
        $workoutData = fn($member) => $member?->workouts->map(fn($workout) => ['id'=>$workout->id,'name'=>$workout->name,'date'=>$workout->starts_at->format('d/m/Y'),'count'=>$workout->items->count(),'open_url'=>route('workouts.show',$workout),'clone_url'=>route('workouts.create',['source_workout_id'=>$workout->id,'member_id'=>$member->id])])->values()->all() ?? [];
        $billingData = function ($member) {
            if (!$member) return ['memberships'=>[], 'charges'=>[], 'open_count'=>0, 'outstanding'=>0];
            $memberships = $member->memberships->map(fn($membership) => ['id'=>$membership->id,'plan'=>$membership->plan->name,'status'=>$membership->status,'price'=>(float)$membership->price,'starts_at'=>$membership->starts_at->format('d/m/Y'),'open_url'=>route('memberships.show',$membership)])->values();
            $allCharges = $member->memberships->flatMap(fn($membership) => $membership->charges->map(fn($charge) => ['id'=>$charge->id,'description'=>$charge->description,'due_date'=>$charge->due_date->format('d/m/Y'),'due_sort'=>$charge->due_date->format('Y-m-d'),'total'=>(float)$charge->total,'paid'=>(float)$charge->paid_amount,'outstanding'=>(float)$charge->outstanding,'status'=>$charge->status,'open_url'=>route('memberships.show',$membership)]));
            $charges = $allCharges->sortByDesc('due_sort')->take(12)->values();
            $openCharges = $allCharges->whereIn('status',['pending','partial','overdue']);
            return ['memberships'=>$memberships->all(),'charges'=>$charges->all(),'open_count'=>$openCharges->count(),'outstanding'=>$openCharges->sum('outstanding')];
        };
        $orderData = fn($member) => $member?->orders->map(fn($order) => ['id'=>$order->id,'date'=>$order->ordered_at->format('d/m/Y H:i'),'total'=>(float)$order->total,'status'=>$order->status,'items'=>$order->items->map(fn($item) => $item->quantity.'× '.$item->product_name)->join(', ')])->values()->all() ?? [];
