    <script>function memberManager(config){const empty=()=>({id:'',name:'',email:'',phone:'',birth_date:'',address:'',active:'1',action:config.storeUrl,workouts:[],billing:{memberships:[],charges:[],open_count:0,outstanding:0},orders:[],assign_url:''});return{modal:false,mode:'create',tab:'data',form:empty(),formatMoney(value){return new Intl.NumberFormat('pt-BR',{style:'currency',currency:'BRL'}).format(Number(value)||0)},statusLabel(status){return{pending:'Pendente',partial:'Parcial',paid:'Pago',overdue:'Vencida',cancelled:'Cancelada'}[status]||status},statusClass(status){return{pending:'bg-amber-50 text-amber-700',partial:'bg-blue-50 text-blue-700',paid:'bg-emerald-50 text-emerald-700',overdue:'bg-red-50 text-red-700',cancelled:'bg-slate-100 text-slate-500'}[status]||'bg-slate-100 text-slate-600'},init(){if(config.initialMode==='edit'&&config.initialMember)this.openEdit(config.initialMember);else if(config.initialMode==='create'){this.mode='create';this.form={...empty(),...(config.initialMember||{})};this.show()}},openCreate(){this.mode='create';this.tab='data';this.form=empty();this.show()},openEdit(item){this.mode='edit';this.tab='data';this.form={...empty(),...item,active:String(item.active)};this.show()},show(){this.modal=true;document.body.classList.add('overflow-hidden');this.$nextTick(()=>this.$refs.nameInput?.focus())},close(){this.modal=false;document.body.classList.remove('overflow-hidden')}}}</script>
